        ActiveAlerts.push("<b>⚠️[NEW] </b>" + name + " : <b>" + valueText + unit + "</b> " + limitRange);
        RecoveredAlerts = RecoveredAlerts.filter(r => !r.includes(name));
    } else {
        // UPDATE EXISTING ALERT
        var isStillNew = ActiveAlerts[alertIndex].includes("[NEW]");
        var prefix = isStillNew ? "<b>⚠️[NEW] </b>" : "";
        ActiveAlerts[alertIndex] = prefix + name + " : <b>" + valueText + unit + "</b> " + limitRange;
    }
} else {
    // RECOVERY
