// 1. Extract Inputs
const timerEnabled = msg.payload.Lt2.T === "1";
const sensorState = Number(msg.payload.Ls1.D);

// 2. Time Math
const now = new Date();
const currentTime = (now.getHours() * 60) + now.getMinutes();
const [onH, onM] = msg.payload.Lt2.On.split(':').map(Number);
const [offH, offM] = msg.payload.Lt2.Of.split(':').map(Number);
const onTotal = (onH * 60) + onM;
const offTotal = (offH * 60) + offM;

// Determine if we are in the scheduled "Light" window
let isScheduledTime = (onTotal < offTotal)
    ? (currentTime >= onTotal && currentTime < offTotal)
    : (currentTime >= onTotal || currentTime < offTotal);

// 3. Transition Grace Period (1 Minute Leeway)
// Check if the current time is exactly at the switch minute or 1 minute after
const isTransitioning = (currentTime === onTotal || 
                         currentTime === (onTotal + 1) % 1440 || 
                         currentTime === offTotal || 
                         currentTime === (offTotal + 1) % 1440);

// 4. Determine Error
let isError = false;

// If we are in the grace period, we skip the error check entirely
if (timerEnabled && !isTransitioning) {
    // Error if: Scheduled for Light but sensor says DARK
    if (isScheduledTime && sensorState === 1) isError = true;
    // Error if: Scheduled for Dark but sensor says LIGHT
    if (!isScheduledTime && sensorState === 0) isError = true;
}

